#include <cstdio>
#include <cstdlib>

static int n;

static bool isSafe(int row, int col, int *board) {
  for (int i = 0; i < row; i++) {
    int c = board[i];
    if (c == col || abs(c - col) == abs(i - row)) {
      return false;
    }
  }
  return true;
}

static void nqueen(int row, int *board, int *count) {
  if (row == n) {
    (*count)++;
    return;
  }
  for (int col = 0; col < n; col++) {
    if (isSafe(row, col, board)) {
      board[row] = col;
      nqueen(row + 1, board, count);
    }
  }
}

int main(int argc, char **argv) {
  if (argc != 2) {
    printf("Usage: %s <board size>\n", argv[0]);
    return 1;
  }
  n = atoi(argv[1]);
  if (n < 1) {
    printf("Board size must be positive\n");
    return 1;
  }

  int total_solutions = 0;

  int max_threads = n;
  int *counts = (int *)malloc(max_threads * sizeof(int));

  for (int i = 0; i < max_threads; i++) {
    counts[i] = 0;
  }

#pragma omp target data map(tofrom: counts[0:max_threads])
{
#pragma omp target teams distribute parallel for thread_limit(256)
  for (int col = 0; col < n; col++) {
    int board[64];
    for (int i = 0; i < n; i++) {
      board[i] = -1;
    }
    board[0] = col;
    int count = 0;
    nqueen(1, board, &count);
    counts[col] = count;
  }
}

  for (int i = 0; i < n; i++) {
    total_solutions += counts[i];
  }

  printf("Total solutions for %d-Queens: %d\n", n, total_solutions);

  free(counts);

  return 0;
}
